WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/44.0/connection.js")}
{!REQUIRESCRIPT("/soap/ajax/44.0/apex.js")}

//Obtenemos el Id de la Transaccion
var idTransaccion= '{!Transaccion__c.Id}';

//Llamamos al Web Services encargado de Generar la Nota de Credito

var result = sforce.apex.execute(
                                  "ws_CrearNotaDeCredito", //Clase a Invocar
                                  "crearNotaDeCredito",    //Metodo a Invocar
                                   {idTransaccion : idTransaccion}//Parametros
                                 );

if(result[0] != ''){

      window.open(result[0],'_blank');

}else{

       alert('No ha sido posible crear la nota de crédito');

}
